// This looks for the first text it can find in the incoming data
const input = $input.first().json;
const rawText = input.text || input.content?.parts?.[0]?.text || input.content;

if (!rawText) {
  throw new Error("Could not find any text to parse. Check the Gemini node output.");
}

// This cleans up any markdown code blocks (```json) Gemini might have added
const cleanText = rawText.replace(/```json|```/g, "").trim();

return JSON.parse(cleanText);

return {
  json: $json,
  binary: {
    data: {
      data: $json.image,
      mimeType: 'image/png',
      fileName: 'blog.png'
    }
  }
};
